def get_altitude(pressure):
    if pressure > 101325 or pressure < 0:
        return 0.0
    p0 = 101325
    return 44330 * (1 - (pressure / p0)**(1 / 5.255))

if __name__ == "__main__":
    print(f"Altitude: {get_altitude(100000)} m")
